SELECT 

spp.title AS plano,
cp."description" AS empresa,
fo.title AS operacao_financeira,
fn.title AS natureza_financeira


from service_billing_configurations AS sp
JOIN service_products AS spp ON spp.id = sp.service_product_id
JOIN companies_places AS cp ON cp.id = sp.company_place_id
JOIN financial_operations AS fo ON fo.id = sp.financial_operation_id
JOIN financers_natures AS fn ON fn.id = sp.financer_nature_id

WHERE sp.service_product_id IN (9425,9564,8595,9804,9805,9806,9807,9808,9634,8484,8834,8590,8594,8487,8838,8839,8842,8843,8844,8845,8846,8847,8864,8837,8985,8955,8989,9097,9122,9278,8536,8508,8514,8516,8513,8518,8522,8523,8546,8550,8515,8511,8545,8526,8525,8521,8538,8539,8549,8535,8519,8524,8517,8527,8547,8505,8520,8542,8540,8548,8503,8543,8510,8537,8534,8529,8512,8507,8531,8528,8541,8504,8506,8532,8530,8544,8575,8565,8605,8552,8630,8626,8608,8625,8602,8568,8645,8644,8633,8619,8610,8606,8593,8641,8599,8559,8640,8555,8642,8577,8607,8558,8564,8554,8603,8571,8637,8604,8578,8553,8585,8588,8632,8573,8631,8646,8556,8601,8570,8551,8589,8569,8635,8634,8636,8600,8615,8620,8647,8609,8648,8572,8618,8617,8612,8639,8623,8638,8614,8611,8621,8616,8622,8613,8629,8649,8627,8628,8624,8650,8567,8587,8584,8583,8679,8680,8651,8653,8674,8670,8669,8664,8667,8673,8671,8676,8652,8663,8678,8654,8665,8677,8668,8675,8666,8672,8658,8657,8655,8656,8662,8661,8660,8833,8836,8533,9040,8659,8986,8988,8835,9039,8987,9275,9277,9276,9279,9280,8509,8566,8574,8592,8560,8562,8561,8581,8557,8563,8580,8596,8598,8643,8579,8586,8582,8597,8591,8576,9488)